let predicateId = 0;

/**
 * Creates a value-based entity filter. Dependencies must be data traits; tags and
 * relations have no single value to provide to the predicate.
 */
export function createPredicate<T extends Trait[]>(
    dependencies: T,
    predicate: (data: { [K in keyof T]: T[K] extends Trait<infer S> ? import('../../trait/types').TraitRecord<S> : never }) => boolean
): Predicate<T> {
    for (const dependency of dependencies) {
        const ctx = dependency[$internal];
        if (ctx.type === 'tag') throw new Error('Predicate dependencies cannot be tags');
        if (ctx.relation) throw new Error('Predicate dependencies cannot be relations');
    }

    return Object.assign(createModifier('predicate', predicateId++, dependencies), { predicate }) as Predicate<T>;
}

export function matchesPredicate(world: import('../../world').World, entity: Entity, predicate: Predicate) {
